// ================= LOADING VEIL =================
window.addEventListener('load', () => {
  setTimeout(() => {
    document.getElementById('veil').classList.add('hide');
  }, 1900);
});

// ================= BUILD CARDS =================
const cardsGrid = document.getElementById('cardsGrid');
cardMessages.forEach((msg, i) => {
  const card = document.createElement('div');
  card.className = 'flip-card reveal-zoom';
  card.innerHTML = `
    <div class="flip-card-inner">
      <div class="flip-front">
        <div class="num">${String(i+1).padStart(2,'0')}</div>
        <h4>Tap to reveal</h4>
        <div class="hint">a quiet thank you</div>
      </div>
      <div class="flip-back"><p>${msg}</p></div>
    </div>`;
  card.addEventListener('click', () => card.classList.toggle('flipped'));
  cardsGrid.appendChild(card);
});

// ================= BUILD SCRAPBOOK GALLERY =================
const scrapbookGrid = document.getElementById('scrapbookGrid');
galleryPhotos.forEach((p, i) => {
  const item = document.createElement('div');
  item.className = 'polaroid reveal-zoom';
  item.innerHTML = `<img src="${p.src}" alt="${p.cap}" loading="lazy"><div class="cap">${p.cap}</div>`;
  item.addEventListener('click', () => openLightbox(p.src, p.cap));
  scrapbookGrid.appendChild(item);
});

// ================= LIGHTBOX =================
const lightbox = document.getElementById('lightbox');
const lbImg = document.getElementById('lbImg');
const lbCap = document.getElementById('lbCap');
function openLightbox(src, cap){
  lbImg.src = src;
  lbCap.textContent = cap;
  lightbox.classList.add('open');
}
document.getElementById('lbClose').addEventListener('click', () => lightbox.classList.remove('open'));
lightbox.addEventListener('click', (e) => { if(e.target === lightbox) lightbox.classList.remove('open'); });
document.addEventListener('keydown', (e) => { if(e.key === 'Escape') lightbox.classList.remove('open'); });

// ================= SCROLL REVEAL =================
const revealEls = document.querySelectorAll('.reveal, .reveal-zoom');
const revealObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if(entry.isIntersecting){
      entry.target.classList.add('in');
    }
  });
}, { threshold: 0.15, rootMargin: '0px 0px -60px 0px' });
revealEls.forEach(el => revealObserver.observe(el));

// ================= OPEN HEART BUTTON =================
document.getElementById('openHeart').addEventListener('click', () => {
  document.getElementById('story').scrollIntoView({ behavior: 'smooth' });
});

// ================= YEAR COUNTER =================
function animateCounter(el, target, duration){
  let startTime = null;
  function step(ts){
    if(!startTime) startTime = ts;
    const progress = Math.min((ts - startTime) / duration, 1);
    const eased = 1 - Math.pow(1 - progress, 3);
    el.textContent = Math.floor(eased * target);
    if(progress < 1) requestAnimationFrame(step);
    else el.textContent = target;
  }
  requestAnimationFrame(step);
}
const yearCounter = document.getElementById('yearCounter');
const statsObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if(entry.isIntersecting){
      animateCounter(yearCounter, 18, 1800);
      statsObserver.disconnect();
    }
  });
}, { threshold: 0.4 });
statsObserver.observe(document.getElementById('statsRow'));

// ================= RANDOM MEMORY BUTTON =================
const randomCard = document.getElementById('randomCard');
const randomBtn = document.getElementById('randomBtn');
let lastIndex = -1;
randomBtn.addEventListener('click', () => {
  let idx;
  do { idx = Math.floor(Math.random() * randomMemories.length); } while(idx === lastIndex && randomMemories.length > 1);
  lastIndex = idx;
  randomCard.style.opacity = 0;
  setTimeout(() => {
    randomCard.querySelector('p').textContent = randomMemories[idx];
    randomCard.style.opacity = 1;
  }, 250);
});

// ================= ENVELOPE =================
const envelope = document.getElementById('envelope');
const envHint = document.getElementById('envHint');
envelope.addEventListener('click', () => {
  if(envelope.classList.contains('open')) return;
  envelope.classList.add('open');
  envHint.style.opacity = '0';
  spawnSparkles();
});
function spawnSparkles(){
  const rect = envelope.getBoundingClientRect();
  for(let i=0;i<10;i++){
    const s = document.createElement('div');
    s.className = 'sparkle';
    s.textContent = '✦';
    s.style.left = (rect.left + Math.random()*rect.width) + 'px';
    s.style.top = (rect.top + rect.height*0.4) + 'px';
    s.style.position = 'fixed';
    s.style.animationDelay = (Math.random()*0.4) + 's';
    document.body.appendChild(s);
    setTimeout(() => s.remove(), 2200);
  }
}

// ================= MUSIC TOGGLE =================
const musicBtn = document.getElementById('musicToggle');
const bgMusic = document.getElementById('bgMusic');
let musicPlaying = false;
musicBtn.addEventListener('click', () => {
  if(musicPlaying){
    bgMusic.pause();
    musicBtn.classList.add('muted');
  } else {
    bgMusic.play().catch(()=>{});
    musicBtn.classList.remove('muted');
  }
  musicPlaying = !musicPlaying;
});

// ================= PROGRESS RAIL =================
const sectionsForRail = ['hero','story','cards','gallery','envelope-section','finale'];
const rail = document.getElementById('progressRail');
sectionsForRail.forEach(id => {
  const dot = document.createElement('div');
  dot.className = 'dot';
  dot.dataset.target = id;
  dot.addEventListener('click', () => document.getElementById(id).scrollIntoView({behavior:'smooth'}));
  rail.appendChild(dot);
});
const railDots = rail.querySelectorAll('.dot');
const railObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if(entry.isIntersecting){
      railDots.forEach(d => d.classList.remove('active'));
      const activeDot = rail.querySelector(`[data-target="${entry.target.id}"]`);
      if(activeDot) activeDot.classList.add('active');
    }
  });
}, { threshold: 0.5 });
sectionsForRail.forEach(id => {
  const el = document.getElementById(id);
  if(el) railObserver.observe(el);
});
